<script setup>import{Head,router,Link}from'@inertiajs/vue3';import{reactive}from'vue';import DriverLayout from'@/Layouts/DriverLayout.vue';defineOptions({layout:DriverLayout});const props=defineProps({plannings:Object,filters:Object,saved:Boolean});const form=reactive({search:props.filters?.search||'',date:props.filters?.date||''});const submit=()=>router.get(route(props.saved?'driver.road-sheets.saved':'driver.road-sheets.index'),form,{preserveState:true,replace:true});const dist=p=>(p.road_sheet?.lines||[]).reduce((s,l)=>s+Number(l.distance||0),0);const d=v=>v?String(v).slice(0,10):'--';</script>
<template><Head :title="saved?'Mes fiches':'Fiches de route'"/><section class="hero"><div><small>ESPACE DRIVER</small><h1>{{saved?'Mes fiches de route':'À compléter'}}</h1><p>{{saved?'Consultez et modifiez vos fiches enregistrées.':'Complétez les fiches affectées à vos missions.'}}</p></div><span class="material-icons-outlined">{{saved?'task_alt':'edit_note'}}</span></section>
<form class="filters" @submit.prevent="submit"><label><span class="material-icons-outlined">search</span><input v-model="form.search" placeholder="Référence dossier"/></label><input v-model="form.date" type="date"/><button>Filtrer</button></form>
<div class="cards"><article v-for="p in plannings.data" :key="p.id"><div class="top"><div><strong>{{p.ref_dossier||'Planning'}}</strong><small>{{p.service?.designation||'Service'}}</small></div><span :class="['status',{saved}]">{{p.road_sheet?.status_label||'À compléter'}}</span></div><p class="client"><span class="material-icons-outlined">group</span>{{(p.planning_clients||[]).map(x=>x.client?.full_name).filter(Boolean).join(', ')||'Client non renseigné'}}</p><div class="dates"><span>{{d(p.date_du)}} → {{d(p.date_au)}}</span><b>{{p.road_sheet?.lines?.length||0}} jour(s)</b></div><div v-if="saved" class="km"><span>Avant service <b>{{Number(p.road_sheet?.pre_service_km||0)}} km</b></span><span>Circuit <b>{{dist(p)}} km</b></span><span>Total <b>{{dist(p)+Number(p.road_sheet?.pre_service_km||0)}} km</b></span></div><Link :href="route('driver.road-sheets.edit',p.id)">{{saved?'Ouvrir et modifier':'Compléter'}}<span class="material-icons-outlined">arrow_forward</span></Link></article></div><div v-if="!plannings.data.length" class="empty">Aucune fiche trouvée.</div>
<div class="pagination"><Link v-for="link in plannings.links" :key="link.label" :href="link.url||'#'" :class="{active:link.active}" v-html="link.label"/></div></template>
<style scoped>.hero{padding:20px;border-radius:24px;background:linear-gradient(135deg,#450a0a,#7f1d1d,#7c3aed);color:#fff;display:flex;align-items:center;justify-content:space-between}.hero small{color:#fecaca;font-weight:900}.hero h1{margin:4px 0;font-size:25px}.hero p{margin:0;color:#fee2e2}.hero>span{font-size:42px}.filters{margin:13px 0;padding:11px;border:1px solid #e2e8f0;border-radius:17px;background:#fff;display:grid;grid-template-columns:minmax(200px,2fr) 1fr auto;gap:8px}.filters label{display:flex;align-items:center;padding-left:9px;border:1px solid #e2e8f0;border-radius:12px;background:#f8fafc}.filters input{width:100%;height:42px;padding:0 10px;border:1px solid #e2e8f0;border-radius:12px;background:#f8fafc}.filters label input{border:0}.filters button{border:0;border-radius:12px;padding:0 17px;background:#dc2626;color:#fff;font-weight:900}.cards{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:12px}.cards article{padding:14px;border:1px solid #e2e8f0;border-radius:20px;background:#fff}.top{display:flex;align-items:flex-start;gap:8px}.top>div{flex:1}.top strong,.top small{display:block}.top small{margin-top:3px;color:#64748b;font-size:10px;font-weight:800}.status{padding:5px 8px;border-radius:99px;background:#fef3c7;color:#b45309;font-size:9px;font-weight:900}.status.saved{background:#dcfce7;color:#15803d}.client{color:#334155;display:flex;align-items:flex-start;gap:6px;font-size:11px;font-weight:800}.client span{font-size:16px;color:#991b1b}.dates{padding:8px;border-radius:11px;background:#f8fafc;display:flex;justify-content:space-between;color:#64748b;font-size:10px}.km{margin-top:8px;display:grid;grid-template-columns:repeat(3,1fr);gap:5px}.km span{padding:7px;border-radius:9px;background:#ede9fe;color:#6d28d9;font-size:8px}.km b{display:block;margin-top:2px;font-size:10px}.cards article>a{margin-top:10px;color:#dc2626;display:flex;align-items:center;justify-content:flex-end;gap:4px;text-decoration:none;font-size:11px;font-weight:900}.cards article>a span{font-size:15px}.empty{padding:35px;background:#fff;text-align:center}.pagination{margin-top:16px;display:flex;justify-content:center;gap:4px}.pagination a{padding:7px 10px;border-radius:9px;background:#fff;text-decoration:none}.pagination a.active{background:#dc2626;color:#fff}@media(max-width:1100px){.cards{grid-template-columns:repeat(2,1fr)}}@media(max-width:700px){.cards,.filters{grid-template-columns:1fr}.filters button{height:42px}.hero{padding:15px}.hero p{font-size:11px}}</style>
